class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> res;
        for (int i = 1; i <= num.size(); i++) {
            string s = num.substr(0, i);
            if (s[0] == '0' && s.size() > 1) continue;
            long long val = stol(s);
            if (val > INT_MAX) continue;
            for (int j = i + 1; j <= num.size(); j++) {
                s = num.substr(0, j);
                string t = num.substr(i, j - i);
                if (t[0] == '0' && t.size() > 1) continue;
                long long val2 = stol(t);
                if (val2 > INT_MAX) continue;
                if (val + val2 > INT_MAX) break;
                res.push_back(val);
                if (res.size() >= 3) return res;
            }
        }
        return {};
    }
};
